  ('islands-6f0ba476-moex-00009', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-d35177eb', 'sub-islands-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年12月31日有調整事項：尚未支付水電費$16,000；預收收入中有$59,000可認列 為服務收入；尚未支付薪資$125,000；預付租金有$54,000 已耗用；電腦設備今年折舊金額為 $8,000；已提供但尚未入帳之客戶服務金額為$286,000。比較調整前及調整後試算表，請問下列 敘述何者正確？', '["資產總額增加$286,000", "負債總額增加$82,000", "收入總額增加$286,000", "保留盈餘增加$83,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "f78fbdb14e03", "answer_pdf_sha1": "f43123b0c751", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00010', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-d35177eb', 'sub-islands-6f0ba476-01', NULL, 'single_choice', '關於會計循環之結帳步驟，下列敘述何者錯誤？', '["若本期損益為負，結帳時會減少保留盈餘之餘額", "結帳後，虛帳戶的餘額為零", "綜合損益表中的其他綜合損益科目不需結帳", "結帳前後比較，普通股股本的餘額不變"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "f78fbdb14e03", "answer_pdf_sha1": "f43123b0c751", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00011', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-d35177eb', 'sub-islands-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年3月5日收到面額$5,000,000，利率2%，90天到期的票據，在3月25日向銀行 貼現，貼現率為6%。請問關於貼現日之分錄，下列何者正確？（1年以360天計，答案四捨五 入至整數）', '["利息收入$5,556", "利息收入$25,000", "利息費用$33,625", "利息費用$58,625"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "f78fbdb14e03", "answer_pdf_sha1": "f43123b0c751", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
